protected static Boolean _isShapeWrittenUsingIndex(Class<?> enumClass, JsonFormat.Value format, boolean fromClass) { JsonFormat.Shape shape = (format == null) ? null : format.getShape(); if (shape == null) { return null; } if (shape == Shape.ANY || shape == Shape.SCALAR) { return null; } if (shape == Shape.STRING || shape == Shape.NATURAL) { return Boolean.FALSE; } if (shape.isNumeric() || (shape == Shape.ARRAY)) { return Boolean.TRUE; } return null; }